import numpy as np

CRISES = {
    'GFC_2008': {'stocks': -0.52, 'bonds': 0.15, 'gold': 0.05},
    'COVID_2020': {'stocks': -0.34, 'bonds': 0.08, 'gold': 0.12},
    'Black_Monday_1987': {'stocks': -0.23, 'bonds': 0.03, 'gold': 0.02}
}

def apply_stress_scenario(portfolio, scenario):
    """
    Apply a stress scenario to a portfolio.
    """
    pnl = 0.0
    for asset, weight in portfolio.items():
        if asset in scenario:
            pnl += weight * scenario[asset]
    return pnl

def run_all_historical_stresses(portfolio):
    """
    Run all historical stress tests.
    """
    results = {}
    for scenario_name, scenario_returns in CRISES.items():
        results[scenario_name] = apply_stress_scenario(portfolio, scenario_returns)
    return results

# Test
portfolio = {
    'stocks': 0.60,
    'bonds': 0.30,
    'gold': 0.10
}

results = run_all_historical_stresses(portfolio)
print('Historical Stress Test Results:')
for scenario, pnl in results.items():
    print(f'  {scenario}: {pnl:.2%}')

worst = min(results.items(), key=lambda x: x[1])
print(f'\nWorst case: {worst[0]} with {worst[1]:.2%} loss')

import numpy as np
from scipy.optimize import minimize

def reverse_stress_test(sensitivities, target_loss, factor_bounds,
                        n_samples=10000):
    """
    Find scenarios causing target loss or worse.
    """
    critical_scenarios = []

    for _ in range(n_samples):
        scenario = {}
        pnl = 0.0

        for factor, (f_min, f_max) in factor_bounds.items():
            shock = np.random.uniform(f_min, f_max)
            scenario[factor] = shock
            if factor in sensitivities:
                pnl += sensitivities[factor] * shock

        if pnl <= target_loss:
            scenario['pnl'] = pnl
            critical_scenarios.append(scenario)

    return critical_scenarios

def find_minimum_stress_for_loss(sensitivities, target_loss, factor_bounds):
    """
    Find the smallest stress scenario causing target loss.
    """
    factors = list(factor_bounds.keys())

    def objective(x):
        # Minimize total stress magnitude
        return np.sum(x**2)

    def constraint(x):
        # P&L <= target_loss
        pnl = sum(sensitivities.get(f, 0) * x[i] for i, f in enumerate(factors))
        return target_loss - pnl  # >= 0 means pnl <= target

    bounds = [(factor_bounds[f][0], factor_bounds[f][1]) for f in factors]
    x0 = np.zeros(len(factors))

    result = minimize(
        objective, x0,
        constraints={'type': 'ineq', 'fun': constraint},
        bounds=bounds
    )

    return {f: result.x[i] for i, f in enumerate(factors)}

# Test
sensitivities = {
    'equity': 600000,
    'credit': -200000,
    'rates': -100000
}

bounds = {
    'equity': (-0.50, 0.20),
    'credit': (-0.02, 0.10),
    'rates': (-0.03, 0.05)
}

target = -200000

np.random.seed(42)
scenarios = reverse_stress_test(sensitivities, target, bounds)

print(f'Found {len(scenarios)} scenarios causing ${-target:,} loss')
if scenarios:
    print('\nSample scenarios:')
    for i, s in enumerate(scenarios[:3]):
        print(f'  Scenario {i+1}:')
        for factor, shock in s.items():
            if factor != 'pnl':
                print(f'    {factor}: {shock:+.2%}')
        print(f'    P&L: ${s["pnl"]:,.0f}')

import numpy as np

class StressTestingFramework:
    """
    Comprehensive stress testing framework.
    """

    def __init__(self, portfolio_value):
        self.portfolio_value = portfolio_value
        self.sensitivities = {}
        self.historical_scenarios = {}
        self.hypothetical_scenarios = {}
        self.results = {}

    def set_sensitivity(self, factor, sensitivity):
        self.sensitivities[factor] = sensitivity

    def add_historical_scenario(self, name, shocks):
        self.historical_scenarios[name] = shocks

    def add_hypothetical_scenario(self, name, shocks, description=''):
        self.hypothetical_scenarios[name] = {
            'shocks': shocks,
            'description': description
        }

    def run_scenario(self, shocks):
        pnl = 0.0
        for factor, shock in shocks.items():
            if factor in self.sensitivities:
                pnl += self.sensitivities[factor] * shock
        return pnl

    def run_all_tests(self):
        self.results = {
            'historical': {},
            'hypothetical': {}
        }

        for name, shocks in self.historical_scenarios.items():
            pnl = self.run_scenario(shocks)
            self.results['historical'][name] = {
                'pnl': pnl,
                'pct': pnl / self.portfolio_value
            }

        for name, data in self.hypothetical_scenarios.items():
            pnl = self.run_scenario(data['shocks'])
            self.results['hypothetical'][name] = {
                'pnl': pnl,
                'pct': pnl / self.portfolio_value,
                'description': data['description']
            }

    def generate_report(self):
        print('=' * 60)
        print('STRESS TEST REPORT')
        print('=' * 60)
        print(f'Portfolio Value: ${self.portfolio_value:,.0f}')
        print()

        print('HISTORICAL SCENARIOS:')
        print('-' * 40)
        for name, result in self.results['historical'].items():
            print(f'{name}:')
            print(f'  P&L: ${result["pnl"]:,.0f} ({result["pct"]:.2%})')
        print()

        print('HYPOTHETICAL SCENARIOS:')
        print('-' * 40)
        for name, result in self.results['hypothetical'].items():
            print(f'{name}: {result["description"]}')
            print(f'  P&L: ${result["pnl"]:,.0f} ({result["pct"]:.2%})')
        print()

        all_pnls = [r['pnl'] for r in self.results['historical'].values()]
        all_pnls += [r['pnl'] for r in self.results['hypothetical'].values()]

        print('SUMMARY:')
        print('-' * 40)
        print(f'Worst case P&L: ${min(all_pnls):,.0f} ({min(all_pnls)/self.portfolio_value:.2%})')
        print(f'Best case P&L: ${max(all_pnls):,.0f} ({max(all_pnls)/self.portfolio_value:.2%})')

# Test
framework = StressTestingFramework(10000000)

framework.set_sensitivity('equity', 6000000)
framework.set_sensitivity('rates', -3000000)
framework.set_sensitivity('credit', -1000000)

framework.add_historical_scenario('GFC_2008', {'equity': -0.52, 'rates': -0.02, 'credit': 0.06})
framework.add_historical_scenario('COVID_2020', {'equity': -0.34, 'rates': -0.01, 'credit': 0.04})

framework.add_hypothetical_scenario(
    'Rate_Shock',
    {'equity': -0.15, 'rates': 0.02, 'credit': 0.02},
    'Rapid interest rate increase scenario'
)

framework.run_all_tests()
framework.generate_report()
